/* OTCSADetail.saAdvancedReceiveSearch */
SELECT a.receipt_id , a.receipt_number as invoice_number , a.receipt_book_number , a.gl_date , a.currency_code , a.entered_receipt_amount , a.entered_balance_amount , a.entered_pending_amount , a.krw_receipt_amount , a.krw_balance_amount , a.krw_pending_amount , a.usd_receipt_amount , a.paymnet_user , a.comments , a.created_user , a.customer_unique_id , a.customer_number , a.customer_name as vendor_name , a.country , a.payment_method , a.vessel_code as segment4 , a.voyage_no as segment5 , a.exchange_rate_type_krw , a.exchange_rate_date_krw , a.exchange_rate_krw , a.exchange_rate_type_usd , a.exchange_rate_date_usd , a.exchange_rate_usd , '' as segment2 , '' as port_code , '210701' as segment3 , ( nvl( a.entered_balance_amount , 0 ) - nvl( a.entered_pending_amount , 0 ) ) as entered_amt , ( nvl( a.usd_balance_amount , 0 ) - nvl( a.usd_pending_amount , 0 ) ) as usd_amt , ( nvl( a.krw_balance_amount , 0 ) - nvl( a.krw_pending_amount , 0 ) ) as won_amt from ear_if_receipt_balance_v a where 1=1
and a.gl_date between to_date( #{fromDate} , 'yyyy-mm-dd' ) and to_date( #{toDate} , 'yyyy-mm-dd' )
and a.customer_unique_id = #{accCode}
and ( ( nvl( a.entered_balance_amount , 0 ) - nvl( a.entered_pending_amount , 0 ) ) > 0 OR ( nvl( a.entered_balance_amount , 0 ) - nvl( a.entered_pending_amount , 0 ) ) < 0 )


/* OTCSADetail.saBalanceCheckSearch */

select a.sa_no, a.cht_in_out_code,COMCODE_INFO_FUNC('CHT_IN_OUT_CODE', a.cht_in_out_code) as cht_in_out_name,
       a.voy_no, a.step_no, a.cntr_no,a.posting_date, a.op_team_code,team_info_func(a.op_team_code) as team_name,
       a.cntr_acc_code,ACC_NAME_FUNC(A.CNTR_ACC_CODE) AS acc_name, ACC_NATION_FUNC(A.CNTR_ACC_CODE) AS nat_code,
       a.vsl_code , vsl_name_func(a.vsl_code) as vsl_name, a.process_sts_flag,
       nat_eng_name_func(acc_nation_func(a.cntr_acc_code)) as nat_name, a.loc_exc_rate, a.wth_flag,
       GET_WTH_TAX_RATE(a.cntr_acc_code, a.cntr_no ) as income_tax_rate,
       a.exc_date, a.exc_rate_type, a.usd_exc_rate, a.usd_loc_rate, a.curcy_code, a.cancel_flag,
       (select b.benef_acc_code from otc_cp_item_head b where a.cntr_no = b.cntr_no) benef_Acc_Code
  from otc_sa_head a
 WHERE a.vsl_code = #{vslCode}
   and a.voy_no = #{voyNo}
   and a.cht_in_out_code = #{chtInOutCode}
   and a.step_no = #{stepNo}

