/* OTCSADetail.openVslSearch */

SELECT distinct segment4 as vsl_code
     , vsl_name_func( segment4 ) as vsl_name
     , segment5 as voy_no
  from ear_if_invoice_balance_v
 where customer_unique_id = #{acc_code}
   and ( nvl( usd_balance_amount , 0 ) - nvl( usd_pending_amount , 0 ) ) > 0

   and segment4 = #{vessel}


   and segment5 = #{voy}

 union all
select distinct segment4 as vsl_code
     , vsl_name_func( segment4 ) as vsl_name
     , segment5 as voy_no
  from ear_if_trx_balance_v
 where customer_unique_id = #{acc_code}
   and ( nvl( usd_balance_amount , 0 ) - nvl( usd_pending_amount , 0 ) ) > 0

   and segment4 = #{vessel}


   and segment5 = #{voy}


