/* OTCSADetail.saWithTaxInvoiceInsert */

INSERT INTO OTC_SA_DETAIL (
     SA_NO
     , SA_SEQ
     , VSL_CODE
     , VOY_NO
     , TRSACT_CODE
     , USD_SA_AMT
     , LOC_SA_AMT
     , KRW_SA_AMT
     , CURCY_CODE
     , EXC_DATE
     , EXC_RATE_TYPE
     , DUE_DATE
     , TERMS_DATE
     , PYMT_HOLD_FLAG
     , PYMT_METH
     , SA_RATE
     , SA_RATE_DUR
     , FACTOR
     , VAT_FLAG
     , TAX_RATE
     , USD_VAT_SA_AMT
     , LOC_VAT_SA_AMT
     , KRW_VAT_SA_AMT
     , BNK_QTY
     , BNK_PRC
     , STL_VSL_CODE
     , STL_VOY_NO
     , STL_CNTR_ACC_CODE
     , USD_EXC_RATE
     , LOC_EXC_RATE
     , USD_LOC_RATE
     , BANK_ACC_ID
     , BANK_ACC_DESC
     , SYS_CRE_DATE
     , SYS_CRE_USER_ID
     , SYS_UPD_DATE
     , SYS_UPD_USER_ID
     , GL_ACC_CODE
     , EVIDENCE_FLAG
)
VALUES (
     #{with_sa_no}
     , #{with_sa_no}
     , #{vsl_code}
     , #{voy_no}
     , #{income_tax_amt_usd}
     , #{income_tax_amt_usd}
     , #{income_tax_amt_krw}
     , #{curcy_code}
     , #{otcSaWithInfo}
     , #{exc_rate_type}
     , #{otcSaWithInfo}
     , #{otcSaWithInfo}
     , #{pymt_hold_flag}
     , #{pymt_meth}
     , 'CLEARING'
     , #{income_tax_base_usd}
     , #{income_tax_rate}
     , 'N'
     , #{vsl_code}
     , #{voy_no}
     , #{cntr_acc_code}
     , #{usd_exc_rate}
     , #{loc_exc_rate}
     , #{usd_loc_rate}
     , #{bank_acc_id}
     , #{bank_acc_desc}
     , #{_sessionUserId}
     , #{_sessionUserId}
     , #{gl_acc_code}
     , #{evidence_flag}
     , #{with_sa_no}
     , #{with_sa_no}
     , #{vsl_code}
     , SYSDATE
     , #{voy_no}
     , SYSDATE
     , #{inhabit_tax_amt_usd}
     , #{inhabit_tax_amt_usd}
     , #{inhabit_tax_amt_krw}
)

