/* OTCSADetail.SoaVsCBAmtCheck2 */
SELECT A.DEVIDED_GROUP -- 배분된 GROUP KEY , MAX( A.VOY_NO ) VOY_NO -- LAST 항차 의미 (조정할 대상 항차) , MAX( A.TRSACT_CODE ) TRSACT_CODE , MAX( A.ORI_SA_RATE_DUR ) ORI_SA_RATE_DUR , MAX( A.ORI_USD_SA_AMT ) ORI_USD_SA_AMT , MAX( A.ORI_LOC_SA_AMT ) ORI_LOC_SA_AMT , MAX( A.ORI_KRW_SA_AMT ) ORI_KRW_SA_AMT , SUM( A.SA_RATE_DUR ) DIVIDED_SA_RATE_DUR , SUM( A.USD_SA_AMT ) DIVIDED_USD_SA_AMT , SUM( A.LOC_SA_AMT ) DIVIDED_LOC_SA_AMT , SUM( A.KRW_SA_AMT ) DIVIDED_KRW_SA_AMT , MAX( A.ORI_SA_RATE_DUR ) - SUM( A.SA_RATE_DUR ) as DIFF_RATE_DUR , MAX( A.ORI_USD_SA_AMT ) - SUM( A.USD_SA_AMT ) as USD_DIFF_AMT , MAX( A.ORI_LOC_SA_AMT ) - SUM( A.LOC_SA_AMT ) as LOC_DIFF_AMT , MAX( A.ORI_KRW_SA_AMT ) - SUM( A.KRW_SA_AMT ) as KRW_DIFF_AMT FROM OTC_SA_CB_DETAIL_UPLOAD A WHERE SA_NO = #{saNo} AND A.TRSACT_CODE IN ( 'A006' , 'A007' , 'A008' , 'A009' , 'H009' , 'H010' , 'A001' , 'A002' , 'A004' , 'A005' , 'H001' , 'H002' , 'A003'
) GROUP BY A.DEVIDED_GROUP


